import "math"

// TravellingSalesman returns minimum cost Hamiltonian cycle using bitmask DP.
func TravellingSalesman(arr []int) int {
	n := arr[0]
	if n <= 1 { return 0 }
	dist := make([][]int, n)
	for i := 0; i < n; i++ {
		dist[i] = make([]int, n)
		for j := 0; j < n; j++ {
			dist[i][j] = arr[1+i*n+j]
		}
	}
	INF := math.MaxInt32 / 2
	full := (1 << uint(n)) - 1
	dp := make([][]int, 1<<uint(n))
	for i := range dp {
		dp[i] = make([]int, n)
		for j := range dp[i] { dp[i][j] = INF }
	}
	dp[1][0] = 0
	for mask := 1; mask <= full; mask++ {
		for i := 0; i < n; i++ {
			if dp[mask][i] >= INF || mask&(1<<uint(i)) == 0 { continue }
			for j := 0; j < n; j++ {
				if mask&(1<<uint(j)) != 0 { continue }
				nm := mask | (1 << uint(j))
				cost := dp[mask][i] + dist[i][j]
				if cost < dp[nm][j] { dp[nm][j] = cost }
			}
		}
	}
	result := INF
	for i := 0; i < n; i++ {
		v := dp[full][i] + dist[i][0]
		if v < result { result = v }
	}
	return result
}

import java.util.Arrays;

public class TravellingSalesman {
    public static int travellingSalesman(int[] arr) {
        int n = arr[0];
        if (n <= 1) return 0;
        int[][] dist = new int[n][n];
        for (int i = 0; i < n; i++)
            for (int j = 0; j < n; j++)
                dist[i][j] = arr[1 + i * n + j];

        int INF = Integer.MAX_VALUE / 2;
        int[][] dp = new int[1 << n][n];
        for (int[] row : dp) Arrays.fill(row, INF);
        dp[1][0] = 0;

        int full = (1 << n) - 1;
        for (int mask = 1; mask <= full; mask++)
            for (int i = 0; i < n; i++) {
                if (dp[mask][i] >= INF || (mask & (1 << i)) == 0) continue;
                for (int j = 0; j < n; j++) {
                    if ((mask & (1 << j)) != 0) continue;
                    int nm = mask | (1 << j);
                    int cost = dp[mask][i] + dist[i][j];
                    if (cost < dp[nm][j]) dp[nm][j] = cost;
                }
            }

        int result = INF;
        for (int i = 0; i < n; i++)
            result = Math.min(result, dp[full][i] + dist[i][0]);
        return result;
    }
}

fun travellingSalesman(arr: IntArray): Int {
    val n = arr[0]
    if (n <= 1) return 0
    val dist = Array(n) { i -> IntArray(n) { j -> arr[1 + i * n + j] } }
    val INF = Int.MAX_VALUE / 2
    val full = (1 shl n) - 1
    val dp = Array(1 shl n) { IntArray(n) { INF } }
    dp[1][0] = 0
    for (mask in 1..full) for (i in 0 until n) {
        if (dp[mask][i] >= INF || mask and (1 shl i) == 0) continue
        for (j in 0 until n) {
            if (mask and (1 shl j) != 0) continue
            val nm = mask or (1 shl j)
            val cost = dp[mask][i] + dist[i][j]
            if (cost < dp[nm][j]) dp[nm][j] = cost
        }
    }
    var result = INF
    for (i in 0 until n) result = minOf(result, dp[full][i] + dist[i][0])
    return result
}

def travelling_salesman(arr: list[int]) -> int:
    n = arr[0]
    if n <= 1:
        return 0
    dist = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            dist[i][j] = arr[1 + i * n + j]

    INF = float('inf')
    dp = [[INF] * n for _ in range(1 << n)]
    dp[1][0] = 0

    for mask in range(1, 1 << n):
        for i in range(n):
            if dp[mask][i] == INF:
                continue
            if not (mask & (1 << i)):
                continue
            for j in range(n):
                if mask & (1 << j):
                    continue
                new_mask = mask | (1 << j)
                cost = dp[mask][i] + dist[i][j]
                if cost < dp[new_mask][j]:
                    dp[new_mask][j] = cost

    full = (1 << n) - 1
    result = INF
    for i in range(n):
        if dp[full][i] + dist[i][0] < result:
            result = dp[full][i] + dist[i][0]

    return int(result)

pub fn travelling_salesman(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    if n <= 1 { return 0; }
    let mut dist = vec![vec![0i32; n]; n];
    for i in 0..n { for j in 0..n { dist[i][j] = arr[1 + i*n + j]; } }
    let inf = i32::MAX / 2;
    let full = (1usize << n) - 1;
    let mut dp = vec![vec![inf; n]; 1 << n];
    dp[1][0] = 0;
    for mask in 1..=full {
        for i in 0..n {
            if dp[mask][i] >= inf || mask & (1 << i) == 0 { continue; }
            for j in 0..n {
                if mask & (1 << j) != 0 { continue; }
                let nm = mask | (1 << j);
                let cost = dp[mask][i] + dist[i][j];
                if cost < dp[nm][j] { dp[nm][j] = cost; }
            }
        }
    }
    let mut result = inf;
    for i in 0..n {
        let v = dp[full][i] + dist[i][0];
        if v < result { result = v; }
    }
    result
}

object TravellingSalesman {
  def travellingSalesman(arr: Array[Int]): Int = {
    val n = arr(0)
    if (n <= 1) return 0
    val dist = Array.tabulate(n, n)((i, j) => arr(1 + i*n + j))
    val INF = Int.MaxValue / 2
    val full = (1 << n) - 1
    val dp = Array.fill(1 << n, n)(INF)
    dp(1)(0) = 0
    for (mask <- 1 to full; i <- 0 until n if dp(mask)(i) < INF && (mask & (1 << i)) != 0; j <- 0 until n if (mask & (1 << j)) == 0) {
      val nm = mask | (1 << j)
      val cost = dp(mask)(i) + dist(i)(j)
      if (cost < dp(nm)(j)) dp(nm)(j) = cost
    }
    var result = INF
    for (i <- 0 until n) result = math.min(result, dp(full)(i) + dist(i)(0))
    result
  }
}

func travellingSalesman(_ arr: [Int]) -> Int {
    let n = arr[0]
    if n <= 1 { return 0 }
    var dist = [[Int]](repeating: [Int](repeating: 0, count: n), count: n)
    for i in 0..<n { for j in 0..<n { dist[i][j] = arr[1 + i*n + j] } }
    let INF = Int.max / 2
    let full = (1 << n) - 1
    var dp = [[Int]](repeating: [Int](repeating: INF, count: n), count: 1 << n)
    dp[1][0] = 0
    for mask in 1...full {
        for i in 0..<n {
            if dp[mask][i] >= INF || mask & (1 << i) == 0 { continue }
            for j in 0..<n {
                if mask & (1 << j) != 0 { continue }
                let nm = mask | (1 << j)
                let cost = dp[mask][i] + dist[i][j]
                if cost < dp[nm][j] { dp[nm][j] = cost }
            }
        }
    }
    var result = INF
    for i in 0..<n { result = min(result, dp[full][i] + dist[i][0]) }
    return result
}

export function travellingSalesman(arr: number[]): number {
    const n = arr[0];
    if (n <= 1) return 0;
    const dist: number[][] = Array.from({ length: n }, (_, i) =>
        Array.from({ length: n }, (_, j) => arr[1 + i * n + j]));
    const INF = Number.MAX_SAFE_INTEGER;
    const full = (1 << n) - 1;
    const dp: number[][] = Array.from({ length: 1 << n }, () => new Array(n).fill(INF));
    dp[1][0] = 0;
    for (let mask = 1; mask <= full; mask++)
        for (let i = 0; i < n; i++) {
            if (dp[mask][i] >= INF || !(mask & (1 << i))) continue;
            for (let j = 0; j < n; j++) {
                if (mask & (1 << j)) continue;
                const nm = mask | (1 << j);
                dp[nm][j] = Math.min(dp[nm][j], dp[mask][i] + dist[i][j]);
            }
        }
    let result = INF;
    for (let i = 0; i < n; i++) result = Math.min(result, dp[full][i] + dist[i][0]);
    return result;
}
